diff --git a/src/services/preferences.service.ts b/src/services/preferences.service.ts
new file mode 100644
index 0000000..c92b0b3
--- /dev/null
+++ b/src/services/preferences.service.ts
@@ -0,0 +1,147 @@
+/**
+ * Preferences service — manages user notification preferences.
+ *
+ * Provides CRUD for user preferences and a lookup method used by
+ * NotificationService to check whether a notification should be sent.
+ *
+ * Depends on:
+ * - PreferencesRepository for data access
+ */
+
+import type { PreferencesRepository } from '../repositories/preferences.repository.js';
+import type {
+  UserPreferences,
+  CreateUserPreferencesInput,
+  UpdateUserPreferencesInput,
+} from '../models/user-preferences.js';
+import type { NotificationType } from '../models/notification.js';
+import { defaultEmailPreferences } from '../models/user-preferences.js';
+import { Logger } from '../utils/logger.js';
+
+let nextId = 1;
+
+function generatePreferencesId(): string {
+  return `pref-${String(nextId++).padStart(4, '0')}`;
+}
+
+export function resetPreferencesIdCounter(): void {
+  nextId = 1;
+}
+
+export class PreferencesService {
+  private logger = new Logger('PreferencesService');
+
+  constructor(private preferencesRepository: PreferencesRepository) {}
+
+  /**
+   * Create preferences for a user. If email settings are partially provided,
+   * they are merged with defaults.
+   */
+  createPreferences(input: CreateUserPreferencesInput): UserPreferences {
+    const existing = this.preferencesRepository.findByUserId(input.userId);
+    if (existing) {
+      throw new Error(`Preferences already exist for user: ${input.userId}`);
+    }
+
+    const defaults = defaultEmailPreferences();
+
+    const emailPrefs = input.email
+      ? {
+          enabled: input.email.enabled ?? defaults.enabled,
+          frequency: input.email.frequency ?? defaults.frequency,
+          categories: input.email.categories ?? defaults.categories,
+        }
+      : defaults;
+
+    const preferences: UserPreferences = {
+      id: generatePreferencesId(),
+      userId: input.userId,
+      email: emailPrefs,
+      createdAt: new Date(),
+      updatedAt: new Date(),
+    };
+
+    this.preferencesRepository.save(preferences);
+    this.logger.info(`Created preferences ${preferences.id} for user ${input.userId}`);
+    return preferences;
+  }
+
+  /**
+   * Get preferences for a user. Returns undefined if none exist.
+   */
+  getPreferences(userId: string): UserPreferences | undefined {
+    return this.preferencesRepository.findByUserId(userId);
+  }
+
+  /**
+   * Update preferences for a user. Merges partial email settings
+   * with existing values.
+   */
+  updatePreferences(userId: string, input: UpdateUserPreferencesInput): UserPreferences {
+    const existing = this.preferencesRepository.findByUserId(userId);
+    if (!existing) {
+      throw new Error(`Preferences not found for user: ${userId}`);
+    }
+
+    const updatedEmail = input.email
+      ? {
+          enabled: input.email.enabled ?? existing.email.enabled,
+          frequency: input.email.frequency ?? existing.email.frequency,
+          categories: input.email.categories ?? existing.email.categories,
+        }
+      : existing.email;
+
+    const updated = this.preferencesRepository.update(existing.id, {
+      email: updatedEmail,
+      updatedAt: new Date(),
+    });
+
+    this.logger.info(`Updated preferences for user ${userId}`);
+    return updated;
+  }
+
+  /**
+   * Delete preferences for a user.
+   */
+  deletePreferences(userId: string): boolean {
+    const existing = this.preferencesRepository.findByUserId(userId);
+    if (!existing) {
+      return false;
+    }
+    this.preferencesRepository.delete(existing.id);
+    this.logger.info(`Deleted preferences for user ${userId}`);
+    return true;
+  }
+
+  /**
+   * Check whether a notification should be sent to a user via email.
+   *
+   * Returns true if:
+   * - The user has no preferences (defaults allow all)
+   * - Email is enabled AND the notification type is subscribed
+   *
+   * Returns false if:
+   * - Email is globally disabled
+   * - The specific notification type is disabled
+   */
+  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
+    const prefs = this.preferencesRepository.findByUserId(userId);
+
+    // No preferences means default behavior: send everything
+    if (!prefs) {
+      return true;
+    }
+
+    if (!prefs.email.enabled) {
+      return false;
+    }
+
+    const category = prefs.email.categories.find((c) => c.type === notificationType);
+    // If the category isn't listed, default to enabled
+    if (!category) {
+      return true;
+    }
+
+    return category.enabled;
+  }
+}

